-- 1. Dover District × Web Design
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'web-design',
  'dover-district',
  'Dover District sits at Britain''s gateway to continental Europe, and that position shapes everything about the businesses here and what they need from their websites. The Port of Dover processes millions of passengers and billions of pounds in freight annually, feeding a logistics and services economy that operates around the clock. Deal has reinvented itself as one of Kent''s most desirable coastal towns, with an independent high street that attracts visitors from across the South East. Sandwich, a medieval Cinque Port, draws heritage tourism and hosts one of golf''s most prestigious championship courses. The district''s 117,000 residents are spread across these three distinct towns and surrounding villages including Aylesham and Shepherdswell. A logistics company near the port needs a completely different website to an independent cafe on Deal''s seafront or a heritage tourism business in Sandwich. We build websites for Dover District businesses that reflect the specific commercial character and audience of each location.',
  'Dover District''s economy is dominated by its position as the UK''s primary Channel crossing point. The Port of Dover is Europe''s busiest roll-on roll-off port, handling approximately seventeen percent of all UK trade in goods. This generates a substantial logistics, freight forwarding, and transport services sector. Dover town itself is undergoing regeneration around the St James development and the waterfront. Deal has experienced a dramatic renaissance, attracting creatives, Londoners relocating, and weekend visitors drawn by its award-winning beach, independent high street, and cultural scene. Sandwich combines medieval heritage with the Royal St George''s Golf Club, attracting premium tourism. Aylesham is a growing residential centre. The White Cliffs, Dover Castle, and the South Foreland Lighthouse draw heritage tourism throughout the year.',
  'Web design investment across Dover District is polarised. Deal''s independent businesses increasingly invest in quality websites that reflect the town''s curated identity. Dover town''s commercial sector is underserved, with many port-adjacent and town centre businesses running outdated sites. Sandwich''s heritage tourism businesses vary widely in digital quality. The logistics sector uses functional but often uninspiring websites that fail to differentiate operators in a competitive market. London freelancers serve some Deal businesses remotely, while Dover town and the surrounding villages have limited access to quality local web design.',
  'Our approach for Dover District clients starts with the specific audience your business serves. A port logistics company needs a site that projects operational credibility to international shipping partners. A Deal independent needs a visually distinctive site that captures the town''s creative coastal identity. A Sandwich heritage business needs a site that communicates authenticity to premium visitors. We design for the audience and location, not a generic district template.',
  '{"population": 117000, "growth": "Deal experiencing significant regeneration and inward migration", "business_districts": ["Port of Dover", "Dover Town Centre", "St James Development", "Deal High Street", "Deal Seafront", "Sandwich", "Aylesham"], "key_fact": "Port of Dover handles 17% of UK goods trade, making it Europe''s busiest ro-ro port"}',
  '[{"title": "Port and logistics businesses with websites that fail to project credibility", "description": "Dover''s logistics and freight sector serves international clients who evaluate potential partners online before making contact. A logistics company with a dated, text-heavy website that looks like it was built a decade ago loses credibility against competitors with modern, professional digital presentations. In an industry where reliability is everything, your website is the first reliability test you face."}, {"title": "Deal independents needing websites that match their curated high street presence", "description": "Deal''s independent shops, galleries, restaurants, and cafes have built a nationally recognised high street identity. But many operate websites that look nothing like the curated, creative experience customers encounter in person. Weekend visitors from London research online before travelling, and a weak website fails to communicate the quality that makes Deal worth the journey."}, {"title": "Sandwich heritage businesses invisible to search-driven visitors", "description": "Sandwich''s medieval streetscape, Cinque Port heritage, and proximity to Royal St George''s generate premium tourism potential. But many heritage businesses operate without websites or with sites so dated they fail basic mobile usability. Visitors planning a Sandwich trip search online, and businesses without a credible web presence simply do not feature in their plans."}]',
  '[{"title": "Industry-appropriate web design for Dover''s logistics sector", "description": "We build websites for Dover''s port and logistics businesses that project the operational credibility international clients expect. Clean, professional design with clear service information, fleet and capability showcases, accreditation displays, and contact systems designed for commercial enquiry handling. Your website becomes a business tool, not just a brochure."}, {"title": "Creative coastal design for Deal''s independent businesses", "description": "We design websites for Deal businesses that capture the town''s distinctive creative identity. Original design that reflects Deal''s coastal character, professional photography integration, seamless booking and shopping functionality, and mobile performance optimised for visitors browsing on the seafront. Your website becomes a natural extension of the Deal experience."}, {"title": "Heritage-authentic design for Sandwich tourism businesses", "description": "For Sandwich businesses, we create websites that communicate heritage authenticity while delivering modern functionality. Design that respects the medieval character of the town, integrated booking systems for tours and experiences, and content structured to rank for the heritage and golf tourism searches that drive premium visitor traffic."}]',
  '[{"question": "Do you work with businesses across the whole Dover District?", "answer": "Yes. We serve clients in Dover town, Deal, Sandwich, Aylesham, Shepherdswell, and surrounding villages. Each project is tailored to the specific location and audience. A port logistics website looks and functions entirely differently from a Deal seafront restaurant site."}, {"question": "Can you build a website for a logistics or freight company?", "answer": "Absolutely. We have experience designing for Dover''s logistics sector, creating sites that project operational credibility through fleet showcases, accreditation displays, service capability information, and commercial contact systems. These sites are built to convert B2B enquiries, not just inform."}, {"question": "How do you design for Deal''s independent creative identity?", "answer": "We spend time understanding Deal''s culture and your specific position within it. No templates. Original design that reflects the coastal, creative character of the town, with photography-led layouts and functionality that serves how Deal''s visitors actually browse, primarily on mobile, often standing on the seafront or walking the high street."}, {"question": "Will my website rank for searches across the district?", "answer": "Every site includes foundational SEO targeting your service areas. We create location-specific content where appropriate so you rank for Dover, Deal, Sandwich, and surrounding area searches independently, maximising visibility across the district rather than just your immediate postcode."}]',
  'lead-gen'
)
ON CONFLICT (service_slug, town_slug) DO UPDATE SET
