-- 3. Dover District × Lead Capture
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'lead-capture',
  'dover-district',
  'Dover District generates website traffic from audiences with fundamentally different needs and timescales. A shipping agent searching for Dover customs brokerage needs a rapid commercial response. A London couple browsing Deal restaurants on a Thursday evening wants instant table availability before they book their Saturday train. A golfer planning a Sandwich trip around Royal St George''s needs to book accommodation and dining together. A Dover homeowner searching for a plumber wants someone who can come today. A single contact form cannot serve any of these audiences properly, let alone all of them. Our lead capture systems are designed for Dover District''s multi-audience reality, deploying different tools for different visitor types so your business converts traffic from the port sector, the coastal lifestyle crowd, the heritage tourist, and the local resident.',
  'Dover District''s lead capture landscape is shaped by its audience diversity. The port and logistics sector generates B2B enquiries with complex requirements and longer decision cycles. Deal''s visitor economy creates time-sensitive weekend planning enquiries, typically Thursday to Friday evenings. Sandwich tourism produces advance booking enquiries from heritage visitors and golfers with higher average spend. Dover town''s residential population generates traditional service enquiries with expectations of fast response. The cross-Channel dimension adds international enquiries from European businesses and travellers unfamiliar with UK service norms.',
  'Lead capture sophistication across Dover District is minimal. Logistics businesses typically rely on email and phone, missing out-of-hours international enquiries. Deal restaurants use third-party booking platforms that take commissions and own the customer relationship. Sandwich tourism businesses vary from no digital booking to third-party platform dependency. Dover town service businesses use basic contact forms with slow manual follow-up. The overall standard leaves enormous conversion potential unrealised.',
  'We design lead capture around each audience segment in Dover District. Logistics enquirers get commercial quote request systems with structured data collection. Deal restaurant browsers get instant reservation widgets with real-time availability. Sandwich tourism visitors get combined booking tools for accommodation, dining, and activities. Dover residential enquirers get rapid response forms with automated acknowledgement. Every system captures the specific information each audience type expects to provide and captures it in a format that accelerates your response.',
  '{"population": 117000, "growth": "Multiple distinct audience types requiring segmented capture", "business_districts": ["Port of Dover", "Deal Seafront", "Sandwich", "Dover Town Centre", "Aylesham"], "key_fact": "Port logistics, coastal lifestyle, heritage tourism, and residential services each need different capture approaches"}',
  '[{"title": "International logistics enquiries arriving when Dover offices are closed", "description": "Shipping agents and logistics buyers in different time zones send enquiries around the clock. A European manufacturer searching for Dover customs brokerage at midday CET reaches your website at eleven in the morning, but if your team is on the quay or in a meeting, the enquiry sits until someone checks email. Without structured capture and automated acknowledgement, international prospects move to the next provider on their list."}, {"title": "Deal weekend visitors booking through third-party platforms", "description": "Deal''s restaurant and accommodation businesses lose commission on every booking that goes through a third-party platform. Visitors planning a Deal trip on Thursday evening want instant confirmation, and without direct booking tools on your website, they default to Booking.com, OpenTable, or Airbnb. You pay commission and lose the customer data."}, {"title": "Golf and heritage visitors planning Sandwich trips without direct business contact", "description": "Visitors planning trips around Royal St George''s and Sandwich''s medieval heritage typically book accommodation, dining, and activities as a package. Without coordinated booking tools, they piece together arrangements through aggregator platforms. Individual Sandwich businesses miss the opportunity to capture the full visit spend through direct relationships."}]',
  '[{"title": "Commercial quote systems for Dover logistics businesses", "description": "We build structured enquiry capture systems for Dover''s port and logistics sector. Commercial quote request forms collect shipment details, service requirements, and timeline information in a format that accelerates your response. Automated acknowledgements confirm receipt instantly, and the captured data feeds directly into your quoting process."}, {"title": "Direct booking tools for Deal''s visitor economy", "description": "We implement reservation widgets, availability checkers, and booking systems directly on your Deal business website. Visitors get instant confirmation without leaving your site. You keep the commission, own the customer data, and build a direct relationship with guests who would otherwise book through a third-party platform."}, {"title": "Combined experience booking for Sandwich tourism", "description": "For Sandwich hospitality businesses, we build booking tools that let visitors plan multiple elements of their visit. Accommodation with dinner options. Guided heritage walks with afternoon tea. Golf trip coordination with local dining. Each booking captures details for your business and creates upsell opportunities that third-party platforms prevent."}]',
  '[{"question": "Can you build lead capture for a logistics company?", "answer": "Yes. We design commercial enquiry systems that collect the structured information your quoting team needs: shipment details, service requirements, timelines, and contact information. The system sends instant acknowledgements and routes enquiries to the right team member based on service type. This is fundamentally different from a consumer contact form."}, {"question": "How do you help Deal restaurants capture direct bookings?", "answer": "We implement direct reservation widgets on your website that check real-time availability and confirm bookings instantly. Integration with your table management system ensures accuracy. The result: visitors book directly, you save on commission, and you own the customer data for future marketing and loyalty building."}, {"question": "Can lead capture work for Sandwich''s golf tourism visitors?", "answer": "Absolutely. We build booking and enquiry tools tailored to golf trip planners who are coordinating accommodation, dining, and activities around their round at Royal St George''s. The capture system collects trip dates, group size, and preferences, allowing you to respond with tailored packages rather than generic availability."}, {"question": "How quickly do captured leads receive a response?", "answer": "Every lead captured through our systems receives an instant automated acknowledgement within seconds. This includes a personalised message confirming receipt, setting expectations for a detailed response, and providing immediate useful information. Your team then follows up with a full response, but the customer never feels ignored."}]',
  'lead-gen'
)
