-- 6. Dover District × Social Media Setup
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'social-media-setup',
  'dover-district',
  'Social media in Dover District operates across three distinct ecosystems. Deal has one of the strongest independent Instagram communities in Kent, driven by creative businesses, food culture, and a visually photogenic seafront that attracts national attention. Dover town''s social media is centred on community Facebook groups where residents recommend local trades and discuss the regeneration. Sandwich''s heritage identity drives engagement through history, architecture, and golf tourism content. A social media presence set up without understanding which ecosystem your business operates in wastes effort on the wrong platform, the wrong content style, and the wrong audience. We build social media profiles for Dover District businesses that are calibrated to the specific platform and audience dynamics of your location.',
  'Dover District''s social media landscape reflects the personality of each town. Deal''s Instagram presence is nationally significant for a town of its size, with food photography, coastal lifestyle content, and independent shopping driving engagement from far beyond Kent. Dover community Facebook groups are actively used for trade recommendations and town centre discussion, with particular engagement around regeneration developments. Sandwich has a growing social presence driven by heritage content, the Kent and East Sussex Railway, and golf tourism. LinkedIn serves the port logistics sector and professional services. The cross-Channel dimension occasionally generates social engagement from French and Belgian visitors.',
  'Social media quality is highest in Deal, where the creative business community drives strong Instagram and social presence as a natural extension of their brand identity. Dover town businesses are inconsistent, with active community groups but variable business page quality. Sandwich businesses are developing their social presence but many remain under-invested. The logistics sector uses LinkedIn but rarely to full effect. The gap between Deal''s social sophistication and the rest of the district creates both a benchmark and an opportunity.',
  'We set up social media for Dover District businesses based on the platform and content style that drives results in each town. Deal businesses get Instagram-first strategies with professional photography integration and booking link optimisation. Dover town trades get Facebook pages built for community group engagement. Sandwich heritage businesses get visual storytelling profiles that blend history with hospitality. Logistics businesses get LinkedIn company pages optimised for B2B credibility. Every profile is branded consistently and configured for the discovery methods specific to each audience.',
  '{"population": 117000, "growth": "Deal''s Instagram community nationally significant for a town its size", "business_districts": ["Deal High Street", "Deal Seafront", "Dover Town Centre", "Sandwich", "Port area"], "key_fact": "Three distinct social ecosystems: Deal Instagram, Dover Facebook groups, Sandwich heritage content"}',
  '[{"title": "Deal businesses with Instagram presence that does not convert to revenue", "description": "Many Deal businesses have Instagram accounts with beautiful seafront photography and strong follower counts, but no strategy connecting social engagement to bookings, sales, or enquiries. Likes from followers in Manchester and Edinburgh are flattering but commercially worthless unless the content drives people to visit, book, or buy."}, {"title": "Dover town businesses invisible in community group recommendations", "description": "When a Dover resident posts in a community Facebook group asking for a reliable plumber, electrician, or restaurant recommendation, businesses without properly set up Facebook pages cannot be tagged, linked, or discovered. These groups generate genuine high-intent referrals, and businesses without profiles are excluded from the district''s most active word-of-mouth channel."}, {"title": "Sandwich heritage businesses missing visual storytelling opportunities", "description": "Sandwich''s medieval architecture, harbour, and heritage events are inherently visual and shareable content. But most Sandwich businesses have no social media presence to capitalise on this. Visitors photograph the town, share it on social media, and tag nobody, because the businesses they visited have no profiles to tag."}]',
  '[{"title": "Conversion-focused Instagram for Deal businesses", "description": "We set up Deal business Instagram profiles that turn engagement into revenue. Direct booking links, shoppable posts, story highlights organised by offering, and call-to-action optimisation that converts followers into customers. Professional photography guidelines ensure your content matches Deal''s visual standard while driving commercial results."}, {"title": "Community-group-ready Facebook for Dover town businesses", "description": "We build and optimise Facebook business pages for Dover town businesses that are ready for community group engagement. Professional branding, complete service information, portfolio galleries, and review collection systems ensure that when a Dover resident recommends your business, the profile they find is complete, credible, and converts."}, {"title": "Heritage visual storytelling for Sandwich businesses", "description": "We create social media profiles for Sandwich businesses that capitalise on the town''s visual appeal. Instagram and Facebook pages set up with heritage-appropriate branding, content templates for architectural and historical storytelling, and tagging strategies that connect your business to the Sandwich visitor experience."}]',
  '[{"question": "Which social platform should my Dover District business prioritise?", "answer": "It depends on your location and audience. Deal businesses need Instagram-first strategies. Dover town trades need Facebook for community group engagement. Sandwich heritage businesses benefit from Instagram and Facebook visual storytelling. Logistics businesses need LinkedIn. We recommend the platform that matches where your specific customers actually discover and evaluate businesses."}, {"question": "How do I make my Deal Instagram generate actual revenue?", "answer": "We set up profiles with direct booking integration, shoppable post configuration, and conversion-optimised call-to-action buttons. Content strategy guidance ensures posts balance aspirational imagery with clear commercial messaging. Every post has a purpose beyond engagement metrics."}, {"question": "Can you set up social media for a port logistics business?", "answer": "Yes. We build LinkedIn company pages that project operational credibility to B2B clients. Fleet imagery, capability showcases, accreditation displays, and industry content positioning that establishes your Dover logistics business as an authority in Channel crossing services. Professional social presence that supports commercial relationship building."}, {"question": "Do you create content or just set up the profiles?", "answer": "This service focuses on professional setup, branding, and optimisation. We provide content templates, photography guidelines, and posting strategy documents so you can maintain your presence effectively. Ongoing content creation and management is available as a separate service if you prefer hands-off social media."}]',
  'trust'
)
ON CONFLICT (service_slug, town_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  local_context = EXCLUDED.local_context,
  competition_landscape = EXCLUDED.competition_landscape,
