  layout_variant = EXCLUDED.layout_variant;

-- 7. Dover District × Digital Marketing
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'digital-marketing',
  'dover-district',
  'Dover District''s digital marketing opportunity is shaped by audiences that most Kent districts simply do not have access to. The port economy connects Dover businesses to international shipping and logistics buyers searching from across Europe. Deal''s national reputation as a creative coastal destination gives local businesses access to a London and South East audience planning weekend visits. Sandwich''s heritage and golf tourism draws premium visitors willing to spend significantly more per visit than the average day-tripper. Meanwhile, the district''s 117,000 residents need local trades, services, and retail just like any other population centre. Each of these audiences requires a completely different marketing approach. Our digital marketing campaigns are built from granular understanding of how each Dover District audience segment searches, browses, and makes purchasing decisions.',
  'Dover District''s digital marketing landscape has four distinct audience layers. International logistics buyers search for UK port services and customs brokerage using specialist terms and commercial platforms. London and South East visitors discover Deal through Instagram, food publications, and lifestyle search terms. Golf and heritage tourists plan Sandwich visits through specialist platforms and premium travel searches. District residents use Google, Facebook, and local directories to find services. The geographic proximity of these audiences within a single district creates a marketing complexity that few areas in Kent share. Seasonal variation adds another dimension, with Deal''s visitor economy peaking in summer and the port operating year-round.',
  'Digital marketing competition in Dover District varies dramatically by audience. Logistics keywords face national competition from freight platforms and larger operators. Deal lifestyle and hospitality keywords compete against national food and travel publications. Sandwich heritage keywords are moderately competitive. Local service keywords for the residential population are relatively uncontested compared to larger Kent towns. The overall landscape offers significant opportunity for businesses willing to invest in segment-specific marketing rather than generic campaigns.',
  'We build Dover District digital marketing campaigns as multi-segment strategies. B2B logistics campaigns target European and UK shipping decision-makers through search and LinkedIn. Deal visitor campaigns reach London lifestyle audiences through Instagram and Google. Sandwich tourism campaigns target premium visitors through heritage and golf interest channels. Residential campaigns reach district residents through local search and social media. Every campaign tracks leads to the specific segment and channel that generated them.',
  '{"population": 117000, "growth": "International, national, and local audiences creating multi-layered opportunity", "business_districts": ["Port of Dover", "Deal", "Sandwich", "Dover Town Centre", "Aylesham"], "key_fact": "Port logistics, Deal lifestyle visitors, Sandwich premium tourists, and local residents form four distinct marketing audiences"}',
  '[{"title": "Marketing to international logistics buyers from a local Dover base", "description": "Dover port logistics businesses need to reach shipping agents, freight managers, and supply chain directors across Europe and the UK. Standard local marketing does not reach this audience. Without specialist B2B digital marketing targeting commercial search terms and professional platforms, Dover logistics firms are invisible to the international buyers who represent their highest-value opportunities."}, {"title": "Deal visitor marketing competing against national publications", "description": "Deal''s national reputation means Time Out, The Guardian, and food magazines regularly feature the town. Individual Deal businesses compete for digital attention against these well-funded publications. Without targeted marketing, your restaurant or shop relies entirely on visitors discovering you on foot rather than through the pre-visit planning that drives most Deal trips."}, {"title": "No attribution linking Dover District marketing to revenue", "description": "Most businesses across the district cannot identify which marketing activity generates their customers. They run ads, post on social media, and hope for the best. Without conversion tracking, budget allocation is guesswork. The logistics company spending on Google Ads has no idea which keywords generate commercial enquiries versus irrelevant clicks."}]',
  '[{"title": "B2B logistics marketing targeting European and UK shipping buyers", "description": "We build digital marketing campaigns for Dover logistics businesses that reach commercial decision-makers. LinkedIn advertising targeting freight and supply chain professionals. Google Ads campaigns bidding on specialist logistics search terms. Trade publication advertising connecting your Dover services to the international shipping community. Every campaign generates qualified commercial enquiries."}, {"title": "Lifestyle and destination campaigns reaching Deal''s visitor audience", "description": "We run digital campaigns targeting London and South East audiences interested in coastal day trips, independent food scenes, and creative destinations. Instagram and Facebook advertising with Deal-specific creative. Google Ads capturing search intent from people planning Deal visits. Retargeting campaigns re-engaging visitors who browsed your site but did not book."}, {"title": "Full-funnel attribution from ad click to revenue across all segments", "description": "Every Dover District campaign includes comprehensive conversion tracking. Logistics businesses see which keywords generate commercial enquiries. Deal hospitality tracks which ads generate bookings. Residential services see which platforms generate calls. Monthly reporting shows your return on investment by segment, enabling informed budget decisions."}]',
  '[{"question": "Can you market a Dover logistics business to international buyers?", "answer": "Yes. We build B2B digital campaigns targeting logistics decision-makers across Europe and the UK. LinkedIn advertising, specialist search term campaigns, and trade publication visibility connect your Dover port services to the commercial audience that represents your highest-value opportunities."}, {"question": "What budget do Deal businesses need for digital marketing?", "answer": "Most Deal hospitality and retail businesses see meaningful results from five hundred to one thousand pounds monthly in ad spend. The investment generates direct bookings and footfall from London and South East visitors who would not have found you otherwise. We provide forecasts based on Deal-specific keyword costs and audience sizes before you commit."}, {"question": "How do you market Sandwich to premium visitors?", "answer": "We target premium audiences through heritage, golf, and luxury travel interest channels. Google Ads capture search intent from people planning heritage trips and golf visits. Social media campaigns reach affluent audiences interested in medieval history and premium experiences. Every campaign positions Sandwich as a destination worth the journey."}, {"question": "How quickly will I see results from digital marketing?", "answer": "Paid advertising generates leads from day one. Google Ads typically produce enquiries within the first week. Social media campaigns build momentum over two to four weeks. B2B logistics campaigns may take slightly longer as commercial decision cycles are longer. We provide weekly reporting from launch."}]',
  'lead-gen'
)
ON CONFLICT (service_slug, town_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  local_context = EXCLUDED.local_context,
  competition_landscape = EXCLUDED.competition_landscape,
  success_approach = EXCLUDED.success_approach,
  local_stats = EXCLUDED.local_stats,
