-- 8. Dover District × Workwear & Print
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'workwear-print',
  'dover-district',
  'Dover District''s varied business landscape demands workwear and print materials that reflect fundamentally different operating environments. A customs broker at the port needs corporate-quality branded clothing that projects international business credibility. A cafe on Deal''s seafront needs staff uniforms that match the town''s creative independent aesthetic. A heritage tour guide in Sandwich needs branded outerwear that communicates authenticity without looking like a theme park costume. A tradesperson covering jobs from Dover to Aylesham needs durable branded workwear that builds trust on residential doorsteps. The district''s diversity means no single workwear or print approach works everywhere. We supply branded materials tailored to the specific commercial context of each Dover District location.',
  'Dover District''s physical business environments range from the industrial port to the creative seafront to the medieval high street. The port area demands workwear that meets commercial and safety standards while projecting professional credibility to international clients. Deal''s independent high street and seafront set a creative presentation standard where staff uniforms contribute to the customer experience. Sandwich''s heritage context requires branded materials that feel appropriate in a medieval setting. Dover town''s residential trades operate in an environment where branded workwear and printed callback materials directly influence trust and referral rates.',
  'Workwear standards across Dover District are highest at the port, where large logistics operators maintain corporate presentation standards, and on Deal''s high street, where the creative business community drives investment in staff presentation. Sandwich''s tourism businesses are increasingly investing in heritage-appropriate branded materials. Dover town trades and smaller businesses have variable workwear quality, with many operating without branded clothing or professional print materials.',
  'We supply Dover District businesses with workwear and print materials designed for their specific operating context. Port businesses get corporate-quality branded clothing that meets commercial standards. Deal independents get creative-quality uniforms and print materials that match the high street''s aesthetic. Sandwich heritage businesses get materials that blend authenticity with professional presentation. Trades get durable workwear that builds trust across the district''s residential areas.',
  '{"population": 117000, "growth": "Port, coastal creative, and heritage environments requiring distinct workwear", "business_districts": ["Port of Dover", "Deal High Street", "Deal Seafront", "Sandwich", "Dover residential areas"], "key_fact": "District spans industrial port, creative seafront, medieval heritage, and residential trades"}',
  '[{"title": "Port logistics staff projecting inconsistent brand image to international clients", "description": "Dover port businesses interact with international shipping partners who expect corporate presentation standards. Staff in mismatched clothing with no visible branding undermine the professional credibility that wins and retains commercial contracts. When your team meets a client at the port, their appearance is your brand''s first impression."}, {"title": "Deal independents needing creative-quality uniforms on a small business budget", "description": "Deal''s high street sets a creative presentation standard that new businesses must match. But independent operators do not have corporate uniform budgets. They need quality branded aprons, printed materials, and staff clothing that feels handpicked rather than mass-produced, at a price point that makes sense for a small seafront business."}, {"title": "Sandwich tourism businesses without heritage-appropriate branded materials", "description": "A walking tour guide in Sandwich in a generic fleece looks like an afterthought. Heritage tourism demands branded materials that communicate knowledge, authority, and authenticity. Without heritage-appropriate workwear and printed materials, Sandwich businesses fail to deliver the premium experience that visitors travelling specifically for the town''s history expect."}]',
  '[{"title": "Corporate-quality branded workwear for Dover port businesses", "description": "We supply embroidered and printed workwear that meets the presentation standards international logistics clients expect. Branded polo shirts, jackets, PPE, and corporate wear that project professionalism at the port, in client meetings, and at trade events. Every item is produced to brand guidelines ensuring a consistent corporate image."}, {"title": "Creative-quality uniforms and print for Deal independents", "description": "We produce staff uniforms, branded aprons, printed menus, packaging, and marketing materials that match Deal''s creative aesthetic. Screen-printed tees, embroidered linen aprons, hand-finished print materials, and branded items that feel curated rather than corporate. Every item reflects the independent spirit that defines Deal''s high street."}, {"title": "Heritage-authentic branded materials for Sandwich tourism", "description": "For Sandwich heritage businesses, we produce branded outerwear, guide materials, printed maps, and souvenir items that feel appropriate to the medieval context. Colour palettes, typography, and finishing that reference the town''s Cinque Port heritage while looking professional and contemporary. Materials that enhance the visitor experience rather than undermining it."}]',
  '[{"question": "Can you supply workwear suitable for port and logistics environments?", "answer": "Yes. We supply branded workwear including hi-vis, safety footwear branding, hard hat identification, and corporate clothing that meets port safety requirements while displaying your brand professionally. Items are produced to the durability standards that daily port operations demand."}, {"question": "Do you produce packaging and print materials for Deal food businesses?", "answer": "Absolutely. We produce custom printed packaging, takeaway bags, branded napkins, menu printing, and promotional materials for Deal''s food businesses. All items are designed to match the creative quality standard that Deal''s independent food scene demands, with sustainable material options available."}, {"question": "What is the minimum order for Dover District workwear?", "answer": "We supply as few as five items for sole traders and small businesses. Volume discounts apply to orders of twenty or more. We hold your brand files on record for convenient reordering. For Deal seasonal businesses that need staff uniforms refreshed annually, we maintain your specifications for repeat orders."}, {"question": "Can you produce heritage-style printed materials for Sandwich businesses?", "answer": "Yes. We produce printed guides, maps, menus, and promotional materials with heritage-appropriate design. This includes specialist finishes, period-influenced typography, and materials that feel authentic within Sandwich''s medieval context. We work with you to find the right balance between historical reference and modern functionality."}]',
  'operational'
)
ON CONFLICT (service_slug, town_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  local_context = EXCLUDED.local_context,
  competition_landscape = EXCLUDED.competition_landscape,
  success_approach = EXCLUDED.success_approach,
  local_stats = EXCLUDED.local_stats,
  pain_points = EXCLUDED.pain_points,
